// ------------------------------------------------------------------
// Parse the WAHA webhook payload into a flat shape used downstream.
// Handles: text, button replies, list replies, group/self detection.
// ------------------------------------------------------------------
const raw = $input.first().json;
const body = raw.body || raw;
const payload = body.payload || {};
const event = body.event || '';
const session = body.session || 'default';

const from = payload.from || '';
const fromMe = payload.fromMe === true;
const isGroup = typeof from === 'string' && (from.endsWith('@g.us') || /^\d+-\d+@/.test(from));
const phoneNumber = typeof from === 'string' ? from.replace('@c.us', '').replace('@g.us', '') : '';
const senderName = payload.notifyName || payload._data?.notifyName || '';

const rawBody = (payload.body || '').toString();
const messageText = rawBody.trim();
const msgLower = messageText.toLowerCase();

// Detect interactive replies across WAHA engines
const selectedButtonId =
  payload.selectedButtonId ||
  payload._data?.selectedButtonId ||
  payload.buttonsResponseMessage?.selectedButtonId ||
  payload.message?.buttonsResponseMessage?.selectedButtonId ||
  '';

const selectedRowId =
  payload.selectedRowId ||
  payload._data?.selectedRowId ||
  payload.listResponseMessage?.singleSelectReply?.selectedRowId ||
  payload.message?.listResponseMessage?.singleSelectReply?.selectedRowId ||
  '';

const isInteractiveReply = !!(selectedButtonId || selectedRowId);
const interactiveId = selectedButtonId || selectedRowId || '';

// Decide whether this webhook should be processed at all
const skip = (
  event !== 'message' ||
  fromMe ||
  isGroup ||
  !from ||
  (!messageText && !isInteractiveReply)
);

return [{ json: {
  event,
  session,
  chatId: from,
  phoneNumber,
  senderName,
  fromMe,
  isGroup,
  messageText,
  msgLower,
  selectedButtonId,
  selectedRowId,
  interactiveId,
  isInteractiveReply,
  skip
} }];

// ------------------------------------------------------------------
// Merge OS env into the webhook item. n8n 2.x task runners often hide
// process.env unless vars are passed into the runner — try several sources.
// If WAHA_BASE_URL is still empty, set FALLBACK_WAHA_BASE_URL below (your
// WAHA host) or fix Docker env on the n8n (+ worker) service.
// ------------------------------------------------------------------
const FALLBACK_WAHA_BASE_URL = 'http://212.224.86.152:3000';

function readEnv() {
  try {
    if (typeof globalThis !== 'undefined' && globalThis.process?.env)
      return globalThis.process.env;
  } catch (_) {}
  try {
    if (typeof process !== 'undefined' && process.env) return process.env;
  } catch (_) {}
  return {};
}

const row = $input.first().json;
const parse = $('Parse Payload').first().json;
const base = { ...parse, ...row };
const env = readEnv();
const trimSlash = (s) => (s || '').toString().replace(/\/+$/, '');

let wahaBaseUrl = trimSlash(env.WAHA_BASE_URL || FALLBACK_WAHA_BASE_URL);
if (!wahaBaseUrl || !/^https?:\/\//i.test(wahaBaseUrl)) {
  throw new Error(
    '[Inject Env Config] WAHA_BASE_URL missing or invalid. Set WAHA_BASE_URL on the n8n ' +
    'container, or edit FALLBACK_WAHA_BASE_URL in this node. Must start with http:// or https://'
  );
}

const wahaApiKey = (env.WAHA_API_KEY || '').toString();
if (!wahaApiKey) {
  throw new Error(
    '[Inject Env Config] WAHA_API_KEY is empty. Set WAHA_API_KEY for the n8n process ' +
    '(same as your WAHA X-Api-Key).'
  );
}

return [{ json: {
  ...base,
  wahaSession: env.WAHA_SESSION || 'default',
  wahaBaseUrl,
  wahaApiKey,
  backendUrl: trimSlash(env.BACKEND_URL || ''),
  backendWaBotKey: (env.BACKEND_WA_BOT_KEY || '').toString(),
  salesRep1: (env.SALES_REP_1 || '').toString(),
  salesRep2: (env.SALES_REP_2 || '').toString(),
  salesRep3: (env.SALES_REP_3 || '').toString(),
  frontendUrl: (env.FRONTEND_URL || '').toString()
} }];

// ------------------------------------------------------------------
// Load + prune sessions from workflow staticData.
// Drops sessions older than 7 days.
// Merge Parse Payload + Inject row so chatId survives if upstream omits fields.
// ------------------------------------------------------------------
const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;
const now = Date.now();
const staticData = $getWorkflowStaticData('global');
const sessions = staticData.sessions || {};

// TTL cleanup
for (const key of Object.keys(sessions)) {
  const u = Date.parse(sessions[key]?.updatedAt || '');
  if (!u || now - u > SEVEN_DAYS_MS) delete sessions[key];
}
staticData.sessions = sessions;

const row = $input.first().json;
const parse = $('Parse Payload').first().json;
const d = { ...parse, ...row };
const chatId = d.chatId;
const session = sessions[chatId] || {
  step: 'new',
  role: null,
  data: {},
  history: [],
  updatedAt: new Date().toISOString()
};

return [{ json: { ...d, session } }];

// ------------------------------------------------------------------
// Force step -> 'menu' if user typed a known menu-trigger keyword.
// Brand new sessions also start at 'menu'.
// ------------------------------------------------------------------
const d = $input.first().json;
const session = d.session || { step: 'new' };
const msg = (d.msgLower || '').trim();
const MENU = new Set([
  'menu', 'hi', 'hello', 'start', 'restart',
  'help', '0', 'back', 'main menu', 'home', 'hey'
]);

let effectiveStep = session.step || 'new';
if (session.step === 'new' || MENU.has(msg)) effectiveStep = 'menu';

// Group all parent_* and school_* steps into one route key for the switch
let routeKey = effectiveStep;
if (effectiveStep.startsWith('awaiting_parent_')) routeKey = 'parent_fsm';
else if (effectiveStep.startsWith('awaiting_school_')) routeKey = 'school_fsm';
else if (effectiveStep === 'awaiting_role') routeKey = 'role';
else if (effectiveStep === 'menu') routeKey = 'menu';
else if (effectiveStep === 'in_other') routeKey = 'other';
else if (effectiveStep === 'lead_done') routeKey = 'menu'; // re-show menu after handoff
else routeKey = 'other';

return [{ json: { ...d, effectiveStep, routeKey } }];

// ------------------------------------------------------------------
// Send the role-picker main menu.
// Returns ONE WAHA sendButtons payload with embedded numbered fallback
// inside the body text (works on every WAHA engine).
// WAHA session name comes from "Inject Env Config" (process.env merge).
// ------------------------------------------------------------------
const d = $input.first().json;
const cfg = $('Inject Env Config').first().json;
const wahaSession = cfg.wahaSession || 'default';
const chatId = d.chatId;
const session = d.session;

const body = [
  "Welcome to Koder Kids! 👋",
  "",
  "Pakistan's leading AI, Coding & Robotics education platform.",
  "",
  "Please tell us who you are:",
  "",
  "1) 👨\u200d👩\u200d👧 Parent",
  "2) 🏫 School",
  "3) 💬 Other",
  "",
  "Tap a button or reply with the number. Type *menu* anytime to come back here."
].join('\n');

const payload = {
  session: wahaSession,
  chatId,
  text: body,
  footer: 'koderkids.pk',
  buttons: [
    { id: 'role_parent', title: 'Parent' },
    { id: 'role_school', title: 'School' },
    { id: 'role_other',  title: 'Other'  }
  ]
};

const newSession = {
  step: 'awaiting_role',
  role: null,
  data: {},
  history: session.history || [],
  updatedAt: new Date().toISOString()
};

return [{ json: {
  chatId,
  phoneNumber: d.phoneNumber,
  senderName: d.senderName,
  wahaSession,
  wahaBaseUrl: d.wahaBaseUrl || cfg.wahaBaseUrl,
  wahaApiKey: d.wahaApiKey || cfg.wahaApiKey,
  _newSession: newSession,
  _waPayload: payload,
  _waEndpoint: 'sendButtons',
  _leadReady: false,
  _leadData: null,
  _branch: 'menu'
} }];

// ------------------------------------------------------------------
// User just clicked a role button (or typed 1/2/3 / parent/school/other).
// Maps to next step:
//   parent -> awaiting_parent_age (start parent FSM, ask age)
//   school -> awaiting_school_name (start school FSM, ask school name)
//   other / unknown -> in_other (hand off to LangChain agent)
// ------------------------------------------------------------------
const d = $input.first().json;
const chatId = d.chatId;
const session = d.session;
const body = (d.msgLower || '').trim();
const btnId = d.interactiveId || '';

let role = null;
if (btnId === 'role_parent' || ['1', 'parent', 'parents', 'p', 'mom', 'dad', 'mother', 'father'].includes(body)) role = 'parent';
else if (btnId === 'role_school' || ['2', 'school', 's', 'teacher', 'principal', 'institute', 'institution'].includes(body)) role = 'school';
else if (btnId === 'role_other' || ['3', 'other', 'others', 'o'].includes(body)) role = 'other';
else role = 'other'; // unknown text -> Other (the helpful agent)

let payload, endpoint, newStep;
const cfg = $('Inject Env Config').first().json;
const wahaSession = cfg.wahaSession || 'default';

if (role === 'parent') {
  newStep = 'awaiting_parent_age';
  endpoint = 'sendButtons';
  payload = {
    session: wahaSession,
    chatId,
    text: [
      'Wonderful! 😊 We teach coding, AI & Robotics to kids 5-16 via home tuition.',
      '',
      'How old is your child?',
      '',
      '1) 5-8 years',
      '2) 9-13 years',
      '3) 14-17 years',
      '',
      'Tap a button or reply with a number.'
    ].join('\n'),
    footer: 'koderkids.pk',
    buttons: [
      { id: 'age_5_8',   title: '5-8 yrs'   },
      { id: 'age_9_13',  title: '9-13 yrs'  },
      { id: 'age_14_17', title: '14-17 yrs' }
    ]
  };
} else if (role === 'school') {
  newStep = 'awaiting_school_name';
  endpoint = 'sendText';
  payload = {
    session: wahaSession,
    chatId,
    text: 'Thanks for your interest in Koder Kids 🏫\n\nWe offer School Collaboration and our Education AI ERP.\n\nTo get started, *please type your school name.*'
  };
} else { // other
  newStep = 'in_other';
  endpoint = 'sendText';
  payload = {
    session: wahaSession,
    chatId,
    text: 'No problem! 💬 Tell me what you need and I will help. You can ask anything about our coding classes, ERP, pricing, or anything else.'
  };
}

const newSession = {
  step: newStep,
  role,
  data: {},
  history: session.history || [],
  updatedAt: new Date().toISOString()
};

return [{ json: {
  chatId,
  phoneNumber: d.phoneNumber,
  senderName: d.senderName,
  wahaSession,
  wahaBaseUrl: d.wahaBaseUrl || cfg.wahaBaseUrl,
  wahaApiKey: d.wahaApiKey || cfg.wahaApiKey,
  _newSession: newSession,
  _waPayload: payload,
  _waEndpoint: endpoint,
  _leadReady: false,
  _leadData: null,
  _branch: 'role'
} }];

// ------------------------------------------------------------------
// PARENT FSM (strict button-only flow except for `name` which is text).
// Steps: age -> city -> laptop -> interest -> name -> lead_done
// ------------------------------------------------------------------
const d = $input.first().json;
const chatId = d.chatId;
const session = d.session;
const data = session.data || {};
const step = session.step;
const body = (d.msgLower || '').trim();
const btnId = d.interactiveId || '';
const cfg = $('Inject Env Config').first().json;
const wahaSession = cfg.wahaSession || 'default';

// ---------- helper: build a buttons payload ----------
function btn(textLines, buttons) {
  return { endpoint: 'sendButtons', payload: { session: wahaSession, chatId, text: textLines.join('\n'), footer: 'koderkids.pk', buttons } };
}
function txt(text) {
  return { endpoint: 'sendText', payload: { session: wahaSession, chatId, text } };
}

// ---------- the 4 button-only ask steps ----------
const ASK_AGE = btn([
  'How old is your child?',
  '',
  '1) 5-8 years',
  '2) 9-13 years',
  '3) 14-17 years',
  '',
  'Tap a button or reply with a number.'
], [
  { id: 'age_5_8',   title: '5-8 yrs'   },
  { id: 'age_9_13',  title: '9-13 yrs'  },
  { id: 'age_14_17', title: '14-17 yrs' }
]);

const ASK_CITY = btn([
  'Which city are you in?',
  '',
  '1) Lahore',
  '2) Islamabad / Rawalpindi',
  '3) Other',
  '',
  'Tap a button or reply with a number.'
], [
  { id: 'city_lahore',    title: 'Lahore'         },
  { id: 'city_islamabad', title: 'ISB/Rawalpindi' },
  { id: 'city_other',     title: 'Other'          }
]);

const ASK_LAPTOP = btn([
  'Does your child have access to a laptop or computer?',
  '',
  '1) Yes',
  '2) No',
  '',
  'Tap a button or reply with a number.'
], [
  { id: 'laptop_yes', title: 'Yes' },
  { id: 'laptop_no',  title: 'No'  }
]);

const ASK_INTEREST = {
  endpoint: 'sendList',
  payload: {
    session: wahaSession,
    chatId,
    title: 'What can we help with?',
    description: 'Pick an option below. If buttons do not show, reply with the number:\n\n1) Courses & Curriculum\n2) Pricing\n3) Free Demo Class\n4) Book a Meeting\n5) Talk to an Advisor',
    buttonText: 'View Options',
    footerText: 'koderkids.pk',
    sections: [{
      title: "I'm interested in...",
      rows: [
        { rowId: 'int_courses',  title: 'Courses',       description: 'Curriculum, books, levels'  },
        { rowId: 'int_pricing',  title: 'Pricing',       description: 'Fees and packages'           },
        { rowId: 'int_demo',     title: 'Free Demo',     description: 'Book a free trial class'     },
        { rowId: 'int_meeting',  title: 'Book Meeting',  description: 'Schedule with our team'      },
        { rowId: 'int_advisor',  title: 'Talk to Advisor', description: 'Personal guidance'         }
      ]
    }]
  }
};

const ASK_NAME = txt('Almost done! 😊 May I have your *name* to complete the registration?');

// ---------- parsers per step ----------
function parseAge() {
  if (btnId === 'age_5_8'   || ['1', '5-8',  '5 to 8',  '5'].includes(body))  return '5-8';
  if (btnId === 'age_9_13'  || ['2', '9-13', '9 to 13'].includes(body))        return '9-13';
  if (btnId === 'age_14_17' || ['3', '14-17', '14 to 17'].includes(body))     return '14-17';
  return null;
}
function parseCity() {
  if (btnId === 'city_lahore'    || ['1', 'lahore', 'lhr'].includes(body))                                 return 'Lahore';
  if (btnId === 'city_islamabad' || ['2', 'islamabad', 'rawalpindi', 'isb', 'isb/rawalpindi'].includes(body)) return 'Islamabad/Rawalpindi';
  if (btnId === 'city_other'     || ['3', 'other'].includes(body))                                          return 'Other';
  return null;
}
function parseLaptop() {
  if (btnId === 'laptop_yes' || ['1', 'yes', 'y', 'yeah', 'yep'].includes(body)) return 'Yes';
  if (btnId === 'laptop_no'  || ['2', 'no',  'n',  'nope'].includes(body))       return 'No';
  return null;
}
function parseInterest() {
  const map = {
    int_courses: 'Courses', int_pricing: 'Pricing', int_demo: 'Free Demo',
    int_meeting: 'Book Meeting', int_advisor: 'Talk to Advisor'
  };
  if (map[btnId]) return map[btnId];
  if (['1', 'courses', 'curriculum'].includes(body))            return 'Courses';
  if (['2', 'pricing', 'price', 'fee', 'fees'].includes(body))  return 'Pricing';
  if (['3', 'demo', 'free demo', 'trial'].includes(body))       return 'Free Demo';
  if (['4', 'meeting', 'book', 'appointment'].includes(body))   return 'Book Meeting';
  if (['5', 'advisor', 'talk', 'consult'].includes(body))       return 'Talk to Advisor';
  return null;
}

// ---------- state machine ----------
let nextStep = step;
let nextData = { ...data };
let send = null;
let leadReady = false;
let leadData = null;
const attempts = (data._attempts || 0) + 1;

function reAsk(prompt, retryHint) {
  // if 2 failed attempts on same step, escalate to Other agent
  if (attempts >= 2) {
    nextStep = 'in_other';
    nextData = { ...data, _attempts: 0 };
    send = txt("Let me hand you over to our assistant who can help in free chat. Type *menu* anytime to restart. 😊");
  } else {
    nextData = { ...data, _attempts: attempts };
    send = retryHint;
    send.payload.text = ("Sorry, I didn't catch that. " + send.payload.text);
  }
}

switch (step) {
  case 'awaiting_parent_age': {
    const age = parseAge();
    if (!age) { reAsk('age', ASK_AGE); break; }
    nextData = { ...data, child_age: age, _attempts: 0 };
    nextStep = 'awaiting_parent_city';
    send = ASK_CITY;
    break;
  }
  case 'awaiting_parent_city': {
    const city = parseCity();
    if (!city) { reAsk('city', ASK_CITY); break; }
    nextData = { ...data, city, _attempts: 0 };
    nextStep = 'awaiting_parent_laptop';
    send = ASK_LAPTOP;
    break;
  }
  case 'awaiting_parent_laptop': {
    const laptop = parseLaptop();
    if (!laptop) { reAsk('laptop', ASK_LAPTOP); break; }
    nextData = { ...data, has_laptop: laptop, _attempts: 0 };
    nextStep = 'awaiting_parent_interest';
    send = ASK_INTEREST;
    break;
  }
  case 'awaiting_parent_interest': {
    const interest = parseInterest();
    if (!interest) { reAsk('interest', ASK_INTEREST); break; }
    nextData = { ...data, interest, _attempts: 0 };
    nextStep = 'awaiting_parent_name';
    send = ASK_NAME;
    break;
  }
  case 'awaiting_parent_name': {
    const name = (d.messageText || '').trim();
    if (name.length < 2) { reAsk('name', ASK_NAME); break; }
    nextData = { ...data, name, _attempts: 0 };
    nextStep = 'lead_done';
    leadReady = true;
    leadData = {
      type: 'parent',
      name,
      phone: d.phoneNumber,
      whatsapp_from: chatId,
      city: nextData.city,
      child_age: nextData.child_age,
      has_laptop: nextData.has_laptop,
      interest: nextData.interest
    };
    send = txt(`Perfect ${name}! 😊 Our representative will contact you very shortly to help with: ${nextData.interest}.\n\nThank you for choosing Koder Kids! Type *menu* anytime to return.`);
    break;
  }
  default: {
    // step entry from awaiting_role->parent: ask first question
    nextStep = 'awaiting_parent_age';
    nextData = {};
    send = ASK_AGE;
  }
}

const newSession = {
  step: nextStep,
  role: 'parent',
  data: nextData,
  history: session.history || [],
  updatedAt: new Date().toISOString()
};

return [{ json: {
  chatId,
  phoneNumber: d.phoneNumber,
  senderName: d.senderName,
  wahaSession,
  wahaBaseUrl: d.wahaBaseUrl || cfg.wahaBaseUrl,
  wahaApiKey: d.wahaApiKey || cfg.wahaApiKey,
  _newSession: newSession,
  _waPayload: send.payload,
  _waEndpoint: send.endpoint,
  _leadReady: leadReady,
  _leadData: leadData,
  _branch: 'parent'
} }];

// ------------------------------------------------------------------
// SCHOOL FSM (button-only except `school_name` and `role_at_school`).
// Steps: school_name -> city -> lab -> interest -> role_at_school -> done
// ------------------------------------------------------------------
const d = $input.first().json;
const chatId = d.chatId;
const session = d.session;
const data = session.data || {};
const step = session.step;
const body = (d.msgLower || '').trim();
const btnId = d.interactiveId || '';
const cfg = $('Inject Env Config').first().json;
const wahaSession = cfg.wahaSession || 'default';

function btn(textLines, buttons) {
  return { endpoint: 'sendButtons', payload: { session: wahaSession, chatId, text: textLines.join('\n'), footer: 'koderkids.pk', buttons } };
}
function txt(text) {
  return { endpoint: 'sendText', payload: { session: wahaSession, chatId, text } };
}

const ASK_SCHOOL_NAME = txt('To get started, *please type your school name.*');

const ASK_CITY = btn([
  'Which city is your school in?',
  '',
  '1) Lahore',
  '2) Islamabad / Rawalpindi',
  '3) Karachi',
  '4) Other',
  '',
  'Tap a button or reply with a number.'
], [
  { id: 'scity_lhr',   title: 'Lahore'         },
  { id: 'scity_isb',   title: 'ISB/Rawalpindi' },
  { id: 'scity_khi',   title: 'Karachi'        },
  { id: 'scity_other', title: 'Other'          }
]);

const ASK_LAB = btn([
  'Does your school have a computer lab?',
  '',
  '1) Yes',
  '2) No',
  '3) Planning to build one',
  '',
  'Tap a button or reply with a number.'
], [
  { id: 'lab_yes', title: 'Yes'      },
  { id: 'lab_no',  title: 'No'       },
  { id: 'lab_pln', title: 'Planning' }
]);

const ASK_INTEREST = {
  endpoint: 'sendList',
  payload: {
    session: wahaSession,
    chatId,
    title: 'What can we help with?',
    description: 'Pick an option. If list does not show, reply with the number:\n\n1) Coding Classes at School\n2) AI & Robotics Program\n3) Education AI ERP\n4) Teacher Training\n5) Full School Partnership',
    buttonText: 'View Options',
    footerText: 'koderkids.pk',
    sections: [{
      title: 'Interested in...',
      rows: [
        { rowId: 'sint_classes',     title: 'Coding Classes',  description: 'On-site coding classes'        },
        { rowId: 'sint_robotics',    title: 'AI & Robotics',   description: 'Hands-on robotics program'     },
        { rowId: 'sint_erp',         title: 'ERP System',      description: 'AI school management ERP'      },
        { rowId: 'sint_training',    title: 'Teacher Training', description: 'Upskill your teachers'        },
        { rowId: 'sint_partnership', title: 'Full Partnership', description: 'End-to-end collaboration'     }
      ]
    }]
  }
};

const ASK_ROLE = txt('Almost done! 😊 May I have your *name and role* at the school? (e.g. "Ahmed, Principal")');

function parseCity() {
  if (btnId === 'scity_lhr'   || ['1', 'lahore', 'lhr'].includes(body))                                  return 'Lahore';
  if (btnId === 'scity_isb'   || ['2', 'islamabad', 'rawalpindi', 'isb'].includes(body))                 return 'Islamabad/Rawalpindi';
  if (btnId === 'scity_khi'   || ['3', 'karachi', 'khi'].includes(body))                                  return 'Karachi';
  if (btnId === 'scity_other' || ['4', 'other'].includes(body))                                           return 'Other';
  return null;
}
function parseLab() {
  if (btnId === 'lab_yes' || ['1', 'yes', 'y'].includes(body))                              return 'Yes';
  if (btnId === 'lab_no'  || ['2', 'no',  'n'].includes(body))                              return 'No';
  if (btnId === 'lab_pln' || ['3', 'planning', 'plan'].includes(body))                      return 'Planning';
  return null;
}
function parseInterest() {
  const map = {
    sint_classes: 'Coding Classes', sint_robotics: 'AI & Robotics', sint_erp: 'ERP System',
    sint_training: 'Teacher Training', sint_partnership: 'Full Partnership'
  };
  if (map[btnId]) return map[btnId];
  if (['1', 'classes', 'coding'].includes(body))                  return 'Coding Classes';
  if (['2', 'robotics', 'ai', 'ai & robotics'].includes(body))    return 'AI & Robotics';
  if (['3', 'erp', 'kodereduai'].includes(body))                  return 'ERP System';
  if (['4', 'training', 'teacher training'].includes(body))       return 'Teacher Training';
  if (['5', 'partnership', 'partner'].includes(body))             return 'Full Partnership';
  return null;
}

let nextStep = step;
let nextData = { ...data };
let send = null;
let leadReady = false;
let leadData = null;
const attempts = (data._attempts || 0) + 1;

function reAsk(prompt) {
  if (attempts >= 2) {
    nextStep = 'in_other';
    nextData = { ...data, _attempts: 0 };
    send = txt("Let me hand you over to our assistant for free chat. Type *menu* anytime to restart. 😊");
  } else {
    nextData = { ...data, _attempts: attempts };
    send = prompt;
    send.payload.text = ("Sorry, I didn't catch that. " + send.payload.text);
  }
}

switch (step) {
  case 'awaiting_school_name': {
    const name = (d.messageText || '').trim();
    if (name.length < 2) { reAsk(ASK_SCHOOL_NAME); break; }
    nextData = { ...data, school_name: name, _attempts: 0 };
    nextStep = 'awaiting_school_city';
    send = ASK_CITY;
    break;
  }
  case 'awaiting_school_city': {
    const city = parseCity();
    if (!city) { reAsk(ASK_CITY); break; }
    nextData = { ...data, city, _attempts: 0 };
    nextStep = 'awaiting_school_lab';
    send = ASK_LAB;
    break;
  }
  case 'awaiting_school_lab': {
    const lab = parseLab();
    if (!lab) { reAsk(ASK_LAB); break; }
    nextData = { ...data, lab, _attempts: 0 };
    nextStep = 'awaiting_school_interest';
    send = ASK_INTEREST;
    break;
  }
  case 'awaiting_school_interest': {
    const interest = parseInterest();
    if (!interest) { reAsk(ASK_INTEREST); break; }
    nextData = { ...data, interest, _attempts: 0 };
    nextStep = 'awaiting_school_role';
    send = ASK_ROLE;
    break;
  }
  case 'awaiting_school_role': {
    const raw = (d.messageText || '').trim();
    if (raw.length < 2) { reAsk(ASK_ROLE); break; }
    // try to split "Name, Role" -> name + role_at_school
    let name = raw, roleAt = '';
    if (raw.includes(',')) {
      const parts = raw.split(',').map(s => s.trim());
      name = parts[0]; roleAt = parts.slice(1).join(', ');
    } else if (raw.includes(' - ')) {
      const parts = raw.split(' - ').map(s => s.trim());
      name = parts[0]; roleAt = parts.slice(1).join(' - ');
    }
    nextData = { ...data, name, role_at_school: roleAt, _attempts: 0 };
    nextStep = 'lead_done';
    leadReady = true;
    leadData = {
      type: 'school',
      name,
      phone: d.phoneNumber,
      whatsapp_from: chatId,
      school_name: nextData.school_name,
      city: nextData.city,
      lab: nextData.lab,
      interest: nextData.interest,
      role_at_school: roleAt
    };
    send = txt(`Perfect! 😊 Our school partnerships team will reach out shortly regarding *${nextData.interest}* at ${nextData.school_name}.\n\nThank you! Type *menu* anytime to return.`);
    break;
  }
  default: {
    nextStep = 'awaiting_school_name';
    nextData = {};
    send = ASK_SCHOOL_NAME;
  }
}

const newSession = {
  step: nextStep,
  role: 'school',
  data: nextData,
  history: session.history || [],
  updatedAt: new Date().toISOString()
};

return [{ json: {
  chatId,
  phoneNumber: d.phoneNumber,
  senderName: d.senderName,
  wahaSession,
  wahaBaseUrl: d.wahaBaseUrl || cfg.wahaBaseUrl,
  wahaApiKey: d.wahaApiKey || cfg.wahaApiKey,
  _newSession: newSession,
  _waPayload: send.payload,
  _waEndpoint: send.endpoint,
  _leadReady: leadReady,
  _leadData: leadData,
  _branch: 'school'
} }];

