// ------------------------------------------------------------------
// Take the LangChain Agent output and:
//  - strip LEAD_DATA:{...} tail if present
//  - build a WAHA sendText payload
//  - emit the new session
// ------------------------------------------------------------------
const agentOut = $input.first().json;
const prep = $('Other Agent Prep').first().json;
const parse = $('Parse Payload').first().json;
const session = prep._session || { history: [] };
const cfg = $('Inject Env Config').first().json;
const wahaSession = prep.wahaSession || cfg.wahaSession || 'default';

const rawReply = (agentOut.output || agentOut.text || 'Sorry, I could not process that. Please try again or type *menu*.').toString();

const MARKER = 'LEAD_DATA:';
let cleanReply = rawReply;
let leadData = null;
const idx = rawReply.indexOf(MARKER);
if (idx !== -1) {
  cleanReply = rawReply.substring(0, idx).trim();
  const tail = rawReply.substring(idx + MARKER.length).trim();
  try {
    const m = tail.match(/\{[\s\S]*\}/);
    if (m) {
      const parsed = JSON.parse(m[0]);
      leadData = {
        type: 'other',
        name: parsed.name || prep.senderName || '',
        phone: parsed.phone || prep.phoneNumber || '',
        whatsapp_from: parse.chatId,
        interest: parsed.interest || '',
        notes: parsed.notes || ''
      };
    }
  } catch (_) { leadData = null; }
}
if (!cleanReply) cleanReply = 'How else can I help you today? 😊';

const leadReady = !!leadData && !!(leadData.phone || leadData.name);

const payload = {
  session: wahaSession,
  chatId: parse.chatId,
  text: cleanReply
};

const newSession = {
  step: leadReady ? 'lead_done' : 'in_other',
  role: 'other',
  data: session.data || {},
  history: session.history || [],
  updatedAt: new Date().toISOString()
};

return [{ json: {
  chatId: parse.chatId,
  phoneNumber: parse.phoneNumber,
  senderName: parse.senderName,
  wahaSession,
  wahaBaseUrl: cfg.wahaBaseUrl,
  wahaApiKey: cfg.wahaApiKey,
  _newSession: newSession,
  _waPayload: payload,
  _waEndpoint: 'sendText',
  _leadReady: leadReady,
  _leadData: leadData,
  _branch: 'other'
} }];

// ------------------------------------------------------------------
// Fan out one sales-notification payload per configured rep.
// Reads SALES_REP_1, SALES_REP_2, SALES_REP_3 from env.
// Each item carries the WAHA sendText payload AND the original lead data.
// ------------------------------------------------------------------
const src = $('Has Lead?').first().json;
const crmResp = $input.first().json;
const lead = src._leadData || {};
const cfg = $('Inject Env Config').first().json;
const wahaSession = src.wahaSession || cfg.wahaSession || 'default';
const leadId = crmResp.id || crmResp.body?.id || null;
const frontend = cfg.frontendUrl || '';

const reps = [
  cfg.salesRep1,
  cfg.salesRep2,
  cfg.salesRep3
].filter(Boolean);

const summary = [
  `🔔 NEW ${(lead.type || 'other').toUpperCase()} LEAD`,
  '',
  `Name: ${lead.name || '-'}`,
  `Phone: ${lead.phone || '-'}`,
  lead.school_name ? `School: ${lead.school_name}` : null,
  lead.city ? `City: ${lead.city}` : null,
  lead.child_age ? `Child Age: ${lead.child_age}` : null,
  lead.has_laptop ? `Has Laptop: ${lead.has_laptop}` : null,
  lead.lab ? `Computer Lab: ${lead.lab}` : null,
  lead.role_at_school ? `Role: ${lead.role_at_school}` : null,
  lead.interest ? `Interest: ${lead.interest}` : null,
  leadId ? `Lead ID: ${leadId}` : null,
  frontend && leadId ? `Open: ${frontend}/crm/leads` : null,
  '',
  'Please follow up shortly! 📞'
].filter(Boolean).join('\n');

return reps.map((to) => ({ json: {
  wahaBaseUrl: src.wahaBaseUrl || cfg.wahaBaseUrl,
  wahaApiKey: src.wahaApiKey || cfg.wahaApiKey,
  _wahaSession: wahaSession,
  _to: to.endsWith('@c.us') ? to : `${to}@c.us`,
  _text: summary,
  _leadId: leadId
} }));

// ------------------------------------------------------------------
// Persist the new session back into staticData.
// ------------------------------------------------------------------
const src = $('Has Lead?').first().json;
const chatId = src.chatId;
const newSession = src._newSession;
const staticData = $getWorkflowStaticData('global');
staticData.sessions = staticData.sessions || {};
staticData.sessions[chatId] = newSession;
return [{ json: { _saved: true, chatId, step: newSession.step, role: newSession.role } }];
